python3 - <<'PY'
import json, os
for path in ['.obsidian/community-plugins.json','.obsidian/core-plugins.json','.obsidian/core-plugins-migration.json']:
    print('\n###',path)
    with open(path) as f: data=json.load(f)
    print(json.dumps(data, ensure_ascii=False, indent=2))
print('\n### COMMUNITY MANIFESTS')
base='.obsidian/plugins'
for d in sorted(os.listdir(base)):
  mp=os.path.join(base,d,'manifest.json')
  if os.path.isfile(mp):
    try:
      x=json.load(open(mp))
    except Exception as e: x={'error':str(e)}
    print(json.dumps({'folder':d, **x},ensure_ascii=False))
print('\n### DATA FILES')
for d in sorted(os.listdir(base)):
  dp=os.path.join(base,d,'data.json')
  if os.path.isfile(dp):
    print('\n##',d)
    print(open(dp).read()[:10000])
PY

